package com.google.gson;
import com.google.gson.internal.LinkedTreeMap;
import java.util.Map;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Field;

public class JsonObjectTest {

  @Test
  public void testEquals_sameInstance() {
    JsonObject jsonObject = new JsonObject();
    assertTrue(jsonObject.equals(jsonObject));
  }

  @Test
  public void testEquals_null() {
    JsonObject jsonObject = new JsonObject();
    assertFalse(jsonObject.equals(null));
  }

  @Test
  public void testEquals_differentClass() {
    JsonObject jsonObject = new JsonObject();
    Object other = new Object();
    assertFalse(jsonObject.equals(other));
  }

  @Test
  public void testEquals_equalMembers() throws Exception {
    JsonObject jsonObject1 = new JsonObject();
    JsonObject jsonObject2 = new JsonObject();

    Field membersField = JsonObject.class.getDeclaredField("members");
    membersField.setAccessible(true);

    LinkedTreeMap<String, JsonElement> membersMock1 = Mockito.spy(new LinkedTreeMap<>(false));
    LinkedTreeMap<String, JsonElement> membersMock2 = Mockito.spy(new LinkedTreeMap<>(false));

    // Override equals method by subclassing LinkedTreeMap to avoid mocking final method
    LinkedTreeMap<String, JsonElement> membersProxy1 = new LinkedTreeMap<String, JsonElement>(false) {
      @Override
      public boolean equals(Object o) {
        return o == membersMock2;
      }
    };

    LinkedTreeMap<String, JsonElement> membersProxy2 = new LinkedTreeMap<String, JsonElement>(false) {
      @Override
      public boolean equals(Object o) {
        return o == membersProxy1;
      }
    };

    // Set the proxies
    membersField.set(jsonObject1, membersProxy1);
    membersField.set(jsonObject2, membersProxy2);

    assertTrue(jsonObject1.equals(jsonObject2));
  }

  @Test
  public void testEquals_unequalMembers() throws Exception {
    JsonObject jsonObject1 = new JsonObject();
    JsonObject jsonObject2 = new JsonObject();

    Field membersField = JsonObject.class.getDeclaredField("members");
    membersField.setAccessible(true);

    LinkedTreeMap<String, JsonElement> membersProxy1 = new LinkedTreeMap<String, JsonElement>(false) {
      @Override
      public boolean equals(Object o) {
        return false;
      }
    };

    LinkedTreeMap<String, JsonElement> membersProxy2 = new LinkedTreeMap<String, JsonElement>(false) {
      @Override
      public boolean equals(Object o) {
        return true;
      }
    };

    membersField.set(jsonObject1, membersProxy1);
    membersField.set(jsonObject2, membersProxy2);

    assertFalse(jsonObject1.equals(jsonObject2));
  }
}

